package com.example.secondphone.controller;
import java.util.List;import org.springframework.http.*;import org.springframework.security.core.Authentication;import org.springframework.web.bind.annotation.*;import com.example.secondphone.dto.*;import com.example.secondphone.service.RepairOrderService;import io.swagger.v3.oas.annotations.tags.Tag;import jakarta.validation.Valid;
@RestController @RequestMapping("/api/member/repairs") @Tag(name="會員維修",description="會員提交並查詢自己的維修申請")
public class MemberRepairController{private final RepairOrderService service;public MemberRepairController(RepairOrderService service){this.service=service;}@PostMapping public ResponseEntity<RepairOrderResponse> submit(Authentication auth,@Valid @RequestBody MemberRepairRequest request){return ResponseEntity.status(HttpStatus.CREATED).body(service.submitForMember(auth.getName(),request));}@GetMapping public List<RepairOrderResponse> list(Authentication auth){return service.getMemberRepairs(auth.getName());}@GetMapping("/{id}") public RepairOrderResponse detail(Authentication auth,@PathVariable Long id){return service.getMemberRepair(auth.getName(),id);}}
